<template>
  <div class="home-container">
    <header class="hero-section">
      <h1>⚡ ProLectura: <span class="highlight">Lectura Rápida</span></h1>
      <p>Entrena tu mente para procesar información a la velocidad del pensamiento.</p>
    </header>

    <div class="dashboard-grid">
      <section class="card config-card">
        <h3>1. Elige tu Nivel</h3>
        <div class="level-selector">
          <button @click="nivel = 'principiante'" :class="{ active: nivel === 'principiante' }">Principiante</button>
          <button @click="nivel = 'intermedio'" :class="{ active: nivel === 'intermedio' }">Intermedio</button>
          <button @click="nivel = 'avanzado'" :class="{ active: nivel === 'avanzado' }">Avanzado</button>
        </div>
        <p class="level-info">Velocidad estimada: <strong>{{ velocidadSugerida }} ppm</strong></p>
      </section>

      <section class="card text-card">
        <h3>2. Tu Material de Práctica</h3>
        <textarea 
          v-model="textoPersonalizado" 
          placeholder="Pega aquí el artículo o libro que deseas practicar hoy..."
        ></textarea>
      </section>
    </div>

    <div class="action-section">
      <button class="start-btn" @click="iniciarSesion">
        ¡Comenzar Entrenamiento!
      </button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'HomeView',
  data() {
    return {
      nivel: 'principiante',
      textoPersonalizado: ''
    }
  },
  computed: {
    velocidadSugerida() {
      const velocidades = { principiante: 200, intermedio: 400, avanzado: 600 };
      return velocidades[this.nivel];
    }
  },
  methods: {
    iniciarSesion() {
      if (!this.textoPersonalizado) {
        alert("Por favor, ingresa un texto para practicar.");
        return;
      }
      console.log("Iniciando sesión en nivel:", this.nivel);
      // Aquí podrías usar el router para ir a una nueva vista de lectura
    }
  }
}
